{
  "domain_analysis": {
    "business_context": "A global logistics platform adding real-time driver earnings breakdown (base pay, per-delivery bonus, tips, deductions) across three jurisdictions with fundamentally different labor classifications, legal requirements, and institutional approval processes. This is a compensation visibility feature operating at the intersection of labor law, payroll accuracy, and driver trust.",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The guaranteed compensation component for a delivery, independent of tips or bonuses. For employees (CA), this must meet or exceed minimum wage when calculated hourly. For contractors (Indonesia), this is the agreed-upon per-task rate." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation awarded per completed delivery, often based on distance, time-of-day surge, or demand conditions." },
      { "term": "Tip", "definition": "Voluntary gratuity from the customer to the driver. In employee jurisdictions, tips must never be counted toward base pay or minimum wage calculations." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings. For employees, deductions are legally constrained (taxes, benefits, authorized withholdings). For contractors, deductions may include platform fees, equipment rental, or insurance contributions." },
      { "term": "Earnings Breakdown", "definition": "The itemized, real-time view of all compensation components for a given period, presented to the driver." },
      { "term": "Driver Classification", "definition": "The legal labor status of the driver in their operating jurisdiction — either Employee or Independent Contractor — which determines applicable compensation rules, deduction constraints, and transparency obligations." },
      { "term": "Works Council Approval (Betriebsrat)", "definition": "In Germany, a legally mandated co-determination process where the works council must formally approve changes to systems that display or affect compensation before they can be deployed to drivers." },
      { "term": "Earnings Period", "definition": "The time window over which earnings are aggregated and displayed — e.g., per-delivery, daily, weekly. The granularity may differ by jurisdiction." },
      { "term": "Net Earnings", "definition": "Gross earnings minus all deductions. The final amount the driver receives or is owed." },
      { "term": "Minimum Wage Floor", "definition": "The legally mandated minimum hourly compensation for employee-classified drivers, against which base pay plus per-delivery bonuses (but NOT tips) must be validated." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every earnings breakdown must display exactly four components: base pay, per-delivery bonus, tips, and deductions. No component may be hidden or aggregated into another.",
      "invariant": true,
      "invariant_justification": "Hiding or merging line items corrupts the transparency guarantee that is both the product feature and a legal requirement in at least one jurisdiction. A breakdown that omits a component is not a breakdown.",
      "testable_assertion": "For any earnings breakdown displayed to a driver, all four components (base pay, per-delivery bonus, tips, deductions) are individually visible with their respective amounts, even when an amount is zero."
    },
    {
      "id": "BR-2",
      "rule": "Tips must never be included in base pay or used to satisfy minimum wage calculations for employee-classified drivers.",
      "invariant": true,
      "invariant_justification": "Under California AB5 and general US labor law, counting tips toward minimum wage for employees is a wage theft violation. This is a legal constraint that cannot be relaxed by policy.",
      "testable_assertion": "When computing whether an employee driver's earnings meet the minimum wage floor, only base pay and per-delivery bonuses are summed; tips are excluded from the calculation."
    },
    {
      "id": "BR-3",
      "rule": "For California employee-classified drivers, the earnings breakdown must be displayed — it is not optional or dismissible. The platform must provide wage transparency as mandated by law.",
      "invariant": true,
      "invariant_justification": "California wage transparency law requires employers to provide itemized wage statements. Allowing the feature to be disabled for CA drivers would put the platform in legal violation.",
      "testable_assertion": "A California-based driver cannot disable, hide, or opt out of the earnings breakdown display."
    },
    {
      "id": "BR-4",
      "rule": "The Germany rollout must not proceed until formal works council (Betriebsrat) approval is recorded in the system. The feature must be gated behind an approval flag per jurisdiction.",
      "invariant": true,
      "invariant_justification": "Deploying compensation display changes without Betriebsrat approval violates German co-determination law (Betriebsverfassungsgesetz §87). This is not a process preference — it is a legal precondition.",
      "testable_assertion": "The earnings breakdown feature returns a blocked/unavailable state for Germany-jurisdiction drivers when the works council approval flag is not set to 'approved'."
    },
    {
      "id": "BR-5",
      "rule": "Deductions for employee-classified drivers must be individually itemized (e.g., tax withholding, benefits, authorized deductions) and each must reference a legal or contractual basis.",
      "invariant": true,
      "invariant_justification": "Lumping employee deductions into a single number without explanation violates itemized wage statement requirements and prevents the driver from verifying that only authorized deductions were taken.",
      "testable_assertion": "Each deduction line item for an employee driver includes a label identifying the deduction type and its authorization basis (e.g., 'Federal Tax Withholding', 'Health Insurance - Employee Contribution')."
    },
    {
      "id": "BR-6",
      "rule": "For independent contractor drivers (Indonesia), deductions such as platform fees and service charges must be clearly labeled, but the platform is not required to provide the same itemization depth as for employees.",
      "invariant": false,
      "invariant_justification": "Indonesian law does not mandate the same pay transparency standards. The level of deduction detail is a business policy choice, not a legal mandate.",
      "testable_assertion": "Each deduction for an Indonesian contractor driver includes at minimum a label (e.g., 'Platform Service Fee') and amount."
    },
    {
      "id": "BR-7",
      "rule": "Earnings data displayed must reflect the current state within the platform's real-time SLA. Stale data must be indicated as such — the display must never show outdated figures without a visible staleness indicator.",
      "invariant": true,
      "invariant_justification": "Displaying stale earnings as if they are current is a form of misrepresentation. In employee jurisdictions, showing inaccurate wage data could constitute a wage statement violation.",
      "testable_assertion": "If earnings data is older than the platform's defined real-time threshold, a staleness indicator (e.g., 'Last updated: X minutes ago') is displayed alongside the breakdown."
    },
    {
      "id": "BR-8",
      "rule": "Net earnings displayed must always equal the arithmetic result: base pay + per-delivery bonus + tips - total deductions. No rounding discrepancy or phantom amounts are permitted.",
      "invariant": true,
      "invariant_justification": "If the displayed net does not equal the sum of displayed components, the breakdown is internally inconsistent and untrustworthy. This is a data integrity constraint.",
      "testable_assertion": "For every earnings breakdown, net_earnings == base_pay + per_delivery_bonus + tips - sum(deductions), with zero tolerance for discrepancy."
    },
    {
      "id": "BR-9",
      "rule": "The earnings breakdown must be presented in the driver's local currency for their operating jurisdiction. No currency conversion ambiguity is permitted.",
      "invariant": true,
      "invariant_justification": "Showing earnings in a foreign currency or without clear denomination would mislead drivers about their actual pay. Currency is tied to the jurisdiction's legal tender.",
      "testable_assertion": "California drivers see amounts in USD, Germany drivers in EUR, Indonesia drivers in IDR. Currency symbol/code is always visible."
    },
    {
      "id": "BR-10",
      "rule": "Driver classification (employee vs. independent contractor) must be determined by jurisdiction, not by driver preference or platform configuration override. Classification drives which rules apply.",
      "invariant": true,
      "invariant_justification": "Labor classification is a matter of law, not choice. Allowing the platform to reclassify a California driver as a contractor to avoid transparency obligations would be illegal.",
      "testable_assertion": "A driver operating in California is always classified as 'employee' in the system regardless of any platform-level configuration. Classification is derived from jurisdiction."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see individually itemized base pay, per-delivery bonus, tips, and itemized deductions with legal basis for each deduction, all in USD, with net earnings that arithmetically reconcile"
    },
    {
      "id": "AC-2",
      "given": "A driver in Germany and the Betriebsrat has NOT approved the feature",
      "when": "They attempt to access the earnings breakdown",
      "then": "The feature is unavailable and a message explains that it is pending approval, without exposing internal process details"
    },
    {
      "id": "AC-3",
      "given": "A driver in Germany and the Betriebsrat HAS approved the feature",
      "when": "They view their earnings breakdown",
      "then": "They see the full earnings breakdown with all components displayed in EUR"
    },
    {
      "id": "AC-4",
      "given": "A driver in Indonesia completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay, per-delivery bonus, tips, and labeled deductions (e.g., platform fee) in IDR, with a reconciling net total"
    },
    {
      "id": "AC-5",
      "given": "A California driver whose base pay + per-delivery bonus for an hour falls below the state minimum wage",
      "when": "The system calculates their earnings",
      "then": "A minimum wage shortfall is flagged for payroll adjustment, and tips are excluded from the minimum wage calculation"
    },
    {
      "id": "AC-6",
      "given": "The earnings data feed is delayed beyond the real-time SLA threshold",
      "when": "A driver views their earnings breakdown",
      "then": "A staleness indicator is displayed showing the last-updated timestamp, and no stale figures are presented as current"
    },
    {
      "id": "AC-7",
      "given": "A California driver views the earnings breakdown feature settings",
      "when": "They attempt to disable or hide the earnings breakdown",
      "then": "No option to disable is available; the breakdown is always shown as legally required"
    },
    {
      "id": "AC-8",
      "given": "Any driver in any jurisdiction views an earnings breakdown",
      "when": "The net earnings amount is compared to the component sum",
      "then": "net_earnings equals base_pay + per_delivery_bonus + tips - total_deductions with zero discrepancy"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver operates across jurisdiction boundaries (e.g., picks up in one jurisdiction, delivers in another)",
      "expected_behavior": "The system must apply the rules of the jurisdiction where the driver is legally classified. If classification is ambiguous due to cross-border operation, the stricter jurisdiction's rules apply until resolved. This case should be escalated for legal review."
    },
    {
      "scenario": "A customer rescinds a tip after it was already displayed in the driver's real-time breakdown",
      "expected_behavior": "The breakdown must update to reflect the tip removal, with a clear audit trail. The tip line item changes and the net total recalculates. The driver should see a notification explaining the adjustment, not a silent change."
    },
    {
      "scenario": "A delivery is disputed or cancelled after partial completion",
      "expected_behavior": "The earnings breakdown must accurately reflect any partial pay, adjusted bonuses, and reversed deductions. No phantom earnings should persist in the display."
    },
    {
      "scenario": "Germany works council approval is revoked after the feature has been live",
      "expected_behavior": "The feature must be immediately gated off for all Germany drivers. Any cached or displayed data should be replaced with the unavailable state. The system must not continue showing breakdowns after approval revocation."
    },
    {
      "scenario": "A driver has zero earnings for a period (e.g., all deliveries cancelled)",
      "expected_behavior": "The breakdown is still displayed with all four components showing zero. The feature must not error or hide when there is nothing to show."
    },
    {
      "scenario": "Deductions exceed gross earnings, resulting in negative net pay",
      "expected_behavior": "The breakdown must display the negative net amount transparently. The system must not clamp to zero or hide the negative balance, as this would misrepresent the driver's financial position."
    },
    {
      "scenario": "Platform fee structure changes mid-pay-period for Indonesian contractors",
      "expected_behavior": "Deliveries completed before the change use the old fee; deliveries after use the new fee. The breakdown must not retroactively apply new fees to already-completed deliveries."
    },
    {
      "scenario": "Real-time data shows a tip, but the payment processor has not yet confirmed the charge",
      "expected_behavior": "Unconfirmed tips should be displayed with a 'pending' indicator. They must not be presented as finalized earnings until payment confirmation is received."
    }
  ],

  "business_impact": {
    "financial": "Correct implementation reduces wage-theft litigation risk in California (penalties can reach $100+ per pay period per violation for itemized wage statement failures under CA Labor Code §226). In Germany, non-compliance with Betriebsrat requirements can result in injunctions halting the feature entirely. Transparent earnings build driver trust, which reduces churn — driver acquisition costs in logistics typically run $300-$1,500 per driver.",
    "operational": "Three distinct jurisdiction rulesets must be maintained simultaneously, increasing configuration complexity. The Betriebsrat approval gate introduces a deployment dependency that cannot be bypassed by engineering timelines. Real-time data SLAs add infrastructure requirements for low-latency earnings computation.",
    "user": "Drivers gain trust and financial clarity, reducing support tickets about pay discrepancies. California drivers receive a legally mandated right. Indonesian contractors gain visibility they are not legally owed, which is a competitive differentiator for driver retention in that market.",
    "risk": "HIGH legal risk if California wage statement rules are violated (class action exposure). MEDIUM risk in Germany if feature ships without Betriebsrat approval (injunction, labor court proceedings). LOW regulatory risk in Indonesia but MEDIUM reputational risk if contractor deductions appear exploitative once made transparent.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Receive legally mandated wage transparency; incorrect implementation exposes them to underpayment and the platform to liability" },
      { "group": "Drivers (Germany)", "impact": "Feature availability depends on works council process; premature rollout could trigger labor disputes" },
      { "group": "Drivers (Indonesia)", "impact": "Gain optional transparency; may surface dissatisfaction if platform fees are perceived as excessive once visible" },
      { "group": "Legal/Compliance Team", "impact": "Must validate jurisdiction-specific rules are correctly encoded; ongoing audit responsibility" },
      { "group": "Works Council (Germany)", "impact": "Must be engaged as a co-decision-maker, not merely notified; has legal veto power" },
      { "group": "Payroll/Finance Team", "impact": "Must ensure displayed figures reconcile exactly with actual payments; any discrepancy is a liability" },
      { "group": "Product Team", "impact": "Must manage a feature with jurisdiction-gated rollout, not a single global launch" },
      { "group": "Customers", "impact": "Indirect: tip transparency may influence tipping behavior; tip rescission flows become visible to drivers" }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is brief and does not address several critical domain questions: (1) how driver classification is determined in the system, (2) whether the German Betriebsrat process has been initiated or what the approval mechanism looks like, (3) what the real-time SLA is, (4) how deductions are categorized per jurisdiction, and (5) whether cross-jurisdiction operations exist. Additionally, two of the three jurisdictions involve legal/regulatory requirements that should be validated by legal counsel, not inferred by engineering or domain analysis alone. The presence of a legal/regulatory dimension without confirmed legal review caps confidence.",
    "high_confidence_areas": [
      "Tips must not count toward minimum wage for CA employees (well-established law)",
      "Betriebsrat approval is a hard prerequisite in Germany (well-established law)",
      "Arithmetic reconciliation of earnings components is a universal invariant",
      "Currency must match operating jurisdiction"
    ],
    "low_confidence_areas": [
      "Exact deduction itemization requirements for California — specific categories need legal validation",
      "German works council scope — whether Betriebsrat approval covers only display or also the underlying data model changes",
      "Indonesian regulatory landscape — assumed minimal requirements but not confirmed with local counsel",
      "Whether drivers operate cross-jurisdiction and how classification is handled in that case",
      "Definition of 'real time' — no SLA specified in the prompt"
    ],
    "assumptions": [
      "Each driver operates in exactly one jurisdiction at a time",
      "Driver classification is determined by jurisdiction and is not configurable",
      "The platform already has payroll infrastructure that computes these components — this feature is about display, not calculation",
      "Tips are paid by customers, not subsidized by the platform",
      "The Betriebsrat approval is a binary gate (approved/not approved), not a graduated process"
    ]
  },

  "escalations": [
    {
      "type": "missing_context",
      "description": "The spec does not define what 'real time' means. Is it per-delivery instant update, sub-minute, sub-5-minute? The staleness indicator logic and infrastructure requirements depend entirely on this definition.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Engineering/Infrastructure Team"],
      "options": ["Define real-time as per-delivery-event-driven (updated on each delivery completion)", "Define real-time as polling with a sub-60-second refresh", "Define real-time as best-effort with mandatory staleness indicator"],
      "recommendation": "Per-delivery-event-driven updates with a staleness indicator fallback when the event pipeline is delayed beyond 60 seconds."
    },
    {
      "type": "missing_context",
      "description": "No legal counsel sign-off is referenced for any of the three jurisdictions. California itemized wage statement requirements (Labor Code §226) have specific mandated fields. German Betriebsrat scope must be confirmed. Indonesian contractor transparency norms need local validation.",
      "affected_stakeholders": ["Legal/Compliance Team", "Drivers (all jurisdictions)", "Executive Leadership"],
      "options": ["Proceed with domain-inferred rules and validate with legal post-implementation", "Block feature development until legal review is complete for all three jurisdictions"],
      "recommendation": "Block California and Germany rollout until legal review confirms the itemization requirements and Betriebsrat scope. Indonesia can proceed with lower risk as a soft-launch market."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'deductions' but does not enumerate what types of deductions exist per jurisdiction or per classification. Employee deductions (taxes, benefits, garnishments) are fundamentally different from contractor deductions (platform fees, insurance opt-ins). The display logic, legal requirements, and data sources differ entirely.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Payroll/Finance Team", "Legal/Compliance Team"],
      "options": ["Define a universal deduction taxonomy with jurisdiction-specific subsets", "Let each jurisdiction define its own deduction categories independently"],
      "recommendation": "Define a universal deduction taxonomy at the domain level with jurisdiction-specific mandatory and optional categories. Employee deductions must be legally enumerated; contractor deductions are platform-defined."
    }
  ],

  "rejection_reasons": []
}

